package equivalent;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Tag;
import org.junit.jupiter.api.Test;

import static equivalent.ClonePairGenericInvocationTestSupport.*;

@Tag("timeout")
class ClonePair5310DifferenceFindingTest {

    private final ClonePair5310 subject = new ClonePair5310();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: no_termination.
     * Difference manifestation: the methods differ in whether they terminate.
     */
    @Test
    @BehavioralDifference(DifferenceType.NO_TERMINATION)
    void methodsDisagreeOnLargePrimeCandidate() {
        Object[] inputs = new Object[]{Integer.MAX_VALUE};
        InvocationOutcome method1Outcome = captureWithTimeout(values -> subject.method1(((Integer) values[0]).intValue()), 200L, inputs);
        InvocationOutcome method2Outcome = captureWithTimeout(values -> subject.method2(((Integer) values[0]).intValue()), 200L, inputs);

        assertCoreOutcome(
            method1Outcome,
            "TIMEOUT",
            null,
            null,
            "java.lang.Object[][Integer(2147483647)]",
            "java.lang.Object[][Integer(2147483647)]"
        );
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Boolean(true)",
            null,
            "java.lang.Object[][Integer(2147483647)]",
            "java.lang.Object[][Integer(2147483647)]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }
}
